/* tms-master-icxct-sql-oracle.xml - insertTTMstIcxct */
INSERT INTO TT_MST_ICXCT	(
	 OWKEY
	,ICKEY
	,CTKEY
	,LOGGRPCD
	,COSTPRICE
	,SALEPRICE
	,VOLTYPE
	,NEWYN
	,USD_COSTPRICE
	,USD_SALEPRICE
	,UNIT_WIDTH
	,UNIT_LENGTH
	,UNIT_HEIGHT
	,ACKEY
	,ORDSTOPTYPE
	,NONIBREASON
	,ORDTYPE
	,INSERTDATE
	,INSERTURKEY
	,UPDATEDATE
	,UPDATEURKEY
 )
VALUES	(
	 #{owkey}
	,#{ickey}
	,#{ctkey}
	,#{loggrpcd}
	,#{costprice}
	,#{saleprice}
	,#{voltype}
	,#{newyn}
	,#{usd_costprice}
	,#{usd_saleprice}
	,#{unit_width}
	,#{unit_length}
	,#{unit_height}
	,#{ackey}
	,#{ordstoptype}
	,#{nonibreason}
	,#{ordtype}
	,#{sysdate}
	,#{surkey}
	,#{sysdate}
	,#{surkey}
)

mapper.update:
/* tms-master-icxct-sql-oracle.xml - updateTTMstIcxct */
UPDATE 	TT_MST_ICXCT
 SET	 LOGGRPCD 		  	  	  = #{loggrpcd}
		,VOLTYPE 				  = #{voltype}
		,NEWYN 				  	  = #{newyn}
		,UNIT_WIDTH 			  = #{unit_width}
		,UNIT_LENGTH 			  = #{unit_length}
		,UNIT_HEIGHT 			  = #{unit_height}
		,ACKEY 				  	  = #{ackey}
		,OBPTKEY  				  = #{obptkey}
		,DCKEY					  = #{dckey}
		,ICGRKEY				  = #{icgrkey}
		,UPDATEDATE   		  	  = #{sysdate}
		,UPDATEURKEY  		  	  = #{surkey}
WHERE	OWKEY = #{owkey}
AND     ICKEY = #{ickey}
AND     CTKEY = #{ctkey}

